/**
 * LLM 回复解析器
 * 从 AI 生成的文本中提取自定义 XML 标签内容
 */
/**
 * Maintenance note:
 * - Keep this file UTF-8 (contains Chinese text).
 * - Avoid shell redirection full-file overwrite (>, >>, Out-File, Set-Content).
 * - Prefer apply_patch/IDE-safe edits to prevent mojibake.
 */

export interface ParsedResponse {
  /** 正文标签（兼容 <maintext>/<maintxt>/<content>/<正文>） */
  mainText: string;
  /** <option>...</option> 包裹的普通选项列表（A-D，不含 E / [Leave] / [Rebirth]） */
  options: string[];
  /** <sum>...</sum> 包裹的小总结 */
  summary: string;
  /** <UpdateVariable>/<update> 包裹的变量更新内容 */
  variableUpdate: string;
  /** <UpdateVariable> 内 <JSONPatch>...</JSONPatch> 的变量更新指令 */
  jsonPatch: string;
  /** 解析基准文本（根据配置可能会去除思维链块） */
  rawText: string;
  /** 是否存在 E 选项 */
  hasOptionE: boolean;
  /** 是否存在 [Leave] 选项 */
  hasLeave: boolean;
  /** 是否存在 [Rebirth] 选项 */
  hasRebirth: boolean;
}

export interface ResponseParserOptions {
  /** 默认 true：禁止匹配思维链（think/thinking）内的 XML 标签 */
  forbidMatchingXmlInsideThink?: boolean;
}

function isLeaveOptionLine(line: string): boolean {
  return /\bleave\b/i.test(line);
}

function isRebirthOptionLine(line: string): boolean {
  return /\brebirth\b/i.test(line);
}

/**
 * 提取单个 XML 标签的内容
 */
function extractTag(text: string, tagName: string): string {
  const escapedTagName = tagName.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
  // 仅匹配“块级位置”标签，避免把正文中示例文本误识别为真实标签
  const regex = new RegExp(`(?:^|[\\r\\n]|>)\\s*<${escapedTagName}(?:\\s[^>]*)?>([\\s\\S]*?)</${escapedTagName}>`, 'ig');
  let match: RegExpExecArray | null;

  while ((match = regex.exec(text)) !== null) {
    const fullMatch = match[0];
    const openTagEnd = fullMatch.indexOf('>');
    if (openTagEnd >= 0) {
      // 过滤“标签示例”写法，如 "<maintext>, <option>"（标签后紧跟逗号）
      const afterOpen = fullMatch.slice(openTagEnd + 1).trimStart();
      const firstChar = afterOpen[0];
      if (firstChar === ',' || firstChar === '，') continue;
    }
    return match[1].trim();
  }

  return '';
}

/**
 * 按顺序尝试多个标签名，返回第一个命中的内容
 */
function extractTagByPriority(text: string, tagNames: string[]): string {
  for (const tagName of tagNames) {
    const content = extractTag(text, tagName);
    if (content) return content;
  }
  return '';
}

function isBlockLevelTagStart(text: string, index: number): boolean {
  if (index <= 0) return true;
  const prevChar = text[index - 1];
  return prevChar === '\n' || prevChar === '\r' || prevChar === '>';
}

/**
 * 正文专用提取：匹配“第一个开标签 + 最后一个闭标签”
 * 并移除中间重复的同名标签，避免正文出现额外 <content>/<maintext> 标签字样
 */
function extractTagFromFirstOpenToLastClose(text: string, tagName: string): string {
  const escapedTagName = tagName.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
  const openRegex = new RegExp(`<\\s*${escapedTagName}(?:\\s[^>]*)?>`, 'ig');
  const closeRegex = new RegExp(`<\\s*\\/\\s*${escapedTagName}\\s*>`, 'ig');

  let firstOpenEnd = -1;
  let openMatch: RegExpExecArray | null;
  while ((openMatch = openRegex.exec(text)) !== null) {
    if (!isBlockLevelTagStart(text, openMatch.index)) continue;
    const afterOpen = text.slice(openRegex.lastIndex).trimStart();
    const firstChar = afterOpen[0];
    // 过滤“标签示例”写法，如 "<maintext>, <option>"
    if (firstChar === ',' || firstChar === '，') continue;
    firstOpenEnd = openRegex.lastIndex;
    break;
  }
  if (firstOpenEnd < 0) return '';

  let lastCloseStart = -1;
  let closeMatch: RegExpExecArray | null;
  while ((closeMatch = closeRegex.exec(text)) !== null) {
    if (closeMatch.index < firstOpenEnd) continue;
    lastCloseStart = closeMatch.index;
  }
  if (lastCloseStart < 0) return '';

  const innerContent = text.slice(firstOpenEnd, lastCloseStart);
  const redundantTagRegex = new RegExp(`<\\s*${escapedTagName}(?:\\s[^>]*)?>|<\\s*\\/\\s*${escapedTagName}\\s*>`, 'ig');
  return innerContent.replace(redundantTagRegex, '').trim();
}

function extractMainTagByPriority(text: string, tagNames: string[]): string {
  for (const tagName of tagNames) {
    const content = extractTagFromFirstOpenToLastClose(text, tagName);
    if (content) return content;
  }
  return '';
}

const BODY_START_MARKER_REGEX = /<!--\s*2\s*[.．。]?\s*正文\s*-->/gi;

function findLastBodyStartMarkerEnd(text: string): number {
  let lastEnd = -1;
  let match: RegExpExecArray | null;

  BODY_START_MARKER_REGEX.lastIndex = 0;
  while ((match = BODY_START_MARKER_REGEX.exec(text)) !== null) {
    lastEnd = BODY_START_MARKER_REGEX.lastIndex;
  }

  return lastEnd;
}

/**
 * 移除思维链块
 * 支持多种变体：<think>, <thinking>, <draft_notes> 及大小写变体等
 * 支持错误闭合（如 <thinking> ... </think>）
 * 支持将最后一个 <!-- 2.正文 --> 视为正文起点，忽略其之前的全部内容
 * 同时处理未闭合的思维链标签（流式传输中可能出现）
 */
function removeThinkBlock(text: string): string {
  const bodyStartMarkerEnd = findLastBodyStartMarkerEnd(text);
  const sourceText = bodyStartMarkerEnd >= 0 ? text.slice(bodyStartMarkerEnd) : text;
  const thinkTagRegex = /<\s*(\/?)\s*(think|thinking|draft_notes)\b[^>]*>/gi;

  let result = '';
  let isInsideThinkBlock = false;
  let lastIndex = 0;
  let match: RegExpExecArray | null;

  while ((match = thinkTagRegex.exec(sourceText)) !== null) {
    const isClosing = match[1] === '/';
    const tagStart = match.index;
    const tagEnd = thinkTagRegex.lastIndex;

    // 仅在思维链外保留内容；思维链内（含标签本身）全部丢弃
    // 特殊处理：孤立的思维链结束符会丢弃其之前的段落
    if (!isInsideThinkBlock) {
      if (!isClosing) {
        result += sourceText.slice(lastIndex, tagStart);
        isInsideThinkBlock = true;
      }
    } else {
      // 思维链里经常会把标签名当作说明文本提到，避免把这些示例误当嵌套块。
      if (isClosing) {
        isInsideThinkBlock = false;
      }
    }

    lastIndex = tagEnd;
  }

  // 仅在未进入未闭合思维链时追加尾部文本
  if (!isInsideThinkBlock) {
    result += sourceText.slice(lastIndex);
  }

  return result.trim();
}

function shouldForbidMatchingXmlInsideThink(options?: ResponseParserOptions): boolean {
  return options?.forbidMatchingXmlInsideThink !== false;
}

function getParserSourceText(text: string, options?: ResponseParserOptions): string {
  return shouldForbidMatchingXmlInsideThink(options) ? removeThinkBlock(text) : text.trim();
}

/**
 * 流式显示时：一旦检测到思维链结束标签，则隐藏结束标签之前的全部文本
 * 支持 </think> / </thinking> / </draft_notes> / <!-- 2.正文 --> 及大小写变体
 */
export function filterStreamingTextAfterThinkEnd(text: string): string {
  if (!text) return '';

  const bodyStartMarkerEnd = findLastBodyStartMarkerEnd(text);
  if (bodyStartMarkerEnd >= 0) {
    return text.slice(bodyStartMarkerEnd).trimStart();
  }

  const closeThinkTagRegex = /<\s*\/\s*(think|thinking|draft_notes)\b[^>]*>/i;
  const closeMatch = closeThinkTagRegex.exec(text);
  if (!closeMatch) return text;

  return text.slice(closeMatch.index + closeMatch[0].length).trimStart();
}

/**
 * 移除正文中的 HTML 注释块（用于隐藏正文内思维链）
 * 但保留注释中的 <image>/<img> 块，避免图片提示词被挪到底部。
 */
function removeHtmlComments(text: string): string {
  const withoutComments = text.replace(/<!--[\s\S]*?(?:-->|$)/g, commentBlock => {
    const preservedImages = extractImageBlocks(commentBlock);
    if (preservedImages.length === 0) return '';
    return `\n${preservedImages.map(block => `<image>${block}</image>`).join('\n\n')}\n`;
  });
  return withoutComments
    .replace(/\r\n/g, '\n')
    .replace(/[ \t]+\n/g, '\n')
    // Keep a single paragraph gap, but collapse large holes left by removed comment blocks.
    .replace(/\n{3,}/g, '\n\n')
    .trim();
}

function normalizeTucaoMarkers(text: string): string {
  return text
    .replace(/&lt;\s*tucao(?:\s+[^&]*?)?&gt;/gi, '<tucao>')
    .replace(/&lt;\s*\/\s*tucao\s*&gt;/gi, '</tucao>')
    .replace(/\[\s*tucao\s*]/gi, '<tucao>')
    .replace(/\[\s*\/\s*tucao\s*]/gi, '</tucao>')
    .replace(/<\s*吐槽(?:\s+[^>]*)?>/gi, '<tucao>')
    .replace(/<\s*\/\s*吐槽\s*>/gi, '</tucao>');
}

function extractTucaoBlocks(text: string): string[] {
  const normalized = normalizeTucaoMarkers(text);
  const result: string[] = [];
  const openRegex = /<\s*tucao(?:\s+[^>]*)?>/gi;
  const closeRegex = /<\s*\/\s*tucao\s*>/gi;

  let cursor = 0;
  openRegex.lastIndex = 0;

  while (openRegex.exec(normalized) !== null) {
    const openEnd = openRegex.lastIndex;
    closeRegex.lastIndex = openEnd;
    const closeMatch = closeRegex.exec(normalized);
    const contentEnd = closeMatch ? closeMatch.index : normalized.length;
    const content = normalized.slice(openEnd, contentEnd).trim();
    if (content.length > 0) {
      result.push(content);
    }

    cursor = closeMatch ? closeRegex.lastIndex : normalized.length;
    openRegex.lastIndex = cursor;
    if (!closeMatch) break;
  }

  return result;
}

/**
 * 提取 <image> / <img> 标签的内容（始终显示，无论是否在正文标签内外）
 */
function extractImageBlocks(text: string): string[] {
  const result: string[] = [];
  const regex = /<\s*(?:image|img)(?:\s[^>]*)?>([\s\S]*?)<\/\s*(?:image|img)\s*>/gi;
  let match: RegExpExecArray | null;
  while ((match = regex.exec(text)) !== null) {
    const content = match[1].trim();
    if (content.length > 0) {
      result.push(content);
    }
  }
  return result;
}

function extractTaggedBlocks(text: string, tagName: string): string[] {
  const escapedTagName = tagName.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
  const result: string[] = [];
  const regex = new RegExp(`<\\s*${escapedTagName}(?:\\s[^>]*)?>([\\s\\S]*?)<\\/\\s*${escapedTagName}\\s*>`, 'gi');
  let match: RegExpExecArray | null;
  while ((match = regex.exec(text)) !== null) {
    const content = match[1].trim();
    if (content.length > 0) {
      result.push(content);
    }
  }
  return result;
}

/**
 * 将正文外的 <image>/<img> 块追加到 mainText
 * 正文内已有的 image 块会保留（由 GameView 的 hideImageTagsForDisplay 去除包装标签）
 */
function appendExternalImageBlocks(mainText: string, fullText: string): string {
  const imageBlocks = extractImageBlocks(fullText);
  if (imageBlocks.length === 0) return mainText;

  // 过滤掉 mainText 中已包含的 image 块（避免重复）
  const externalBlocks = imageBlocks.filter(block => !mainText.includes(block));
  if (externalBlocks.length === 0) return mainText;

  const merged = externalBlocks.map(block => `<image>${block}</image>`).join('\n\n');
  return [mainText, merged].filter(part => part && part.trim().length > 0).join('\n\n');
}

function appendExternalTaggedBlocks(mainText: string, fullText: string, tagName: string): string {
  const blocks = extractTaggedBlocks(fullText, tagName);
  if (blocks.length === 0) return mainText;

  const externalBlocks = blocks.filter(block => !mainText.includes(block));
  if (externalBlocks.length === 0) return mainText;

  const merged = externalBlocks.map(block => `<${tagName}>\n${block}\n</${tagName}>`).join('\n\n');
  return [mainText, merged].filter(part => part && part.trim().length > 0).join('\n\n');
}

function appendExternalDisplayBlocks(mainText: string, fullText: string): string {
  let mergedText = appendExternalTaggedBlocks(mainText, fullText, 'catsay');
  mergedText = appendExternalTaggedBlocks(mergedText, fullText, 'SexualScene');
  return appendExternalImageBlocks(mergedText, fullText);
}

/**
 * 解析选项文本为选项数组
 * 每行一个选项，格式如 "A. xxx", "B. xxx" 等
 */
function parseOptions(optionText: string): string[] {
  if (!optionText) return [];
  return optionText
    .split('\n')
    .map(line => line.trim())
    .filter(line => line.length > 0);
}

/**
 * 解析 LLM 回复文本，提取各标签内容
 */
export function parseResponse(text: string, options?: ResponseParserOptions): ParsedResponse {
  // 可配置：是否移除思维链后再匹配 XML 标签
  const cleanText = getParserSourceText(text, options);

  // 提取各标签
  const mainTextRaw = extractMainTagByPriority(cleanText, ['maintext', 'maintxt', 'content', '正文']);
  let mainText = removeHtmlComments(mainTextRaw);
  const mainHasTucao = /<\s*\/?\s*(?:tucao|吐槽)\b|\[\s*\/?\s*tucao\s*]|&lt;\s*\/?\s*tucao\b/i.test(mainTextRaw);
  if (!mainHasTucao) {
    const fallbackTucao = extractTucaoBlocks(cleanText);
    if (fallbackTucao.length > 0) {
      const merged = fallbackTucao.map(block => `<tucao>\n${block}\n</tucao>`).join('\n\n');
      mainText = [mainText, merged].filter(part => part && part.trim().length > 0).join('\n\n');
    }
  }
  // <image>/<img> 标签内容始终显示，追加正文外的 image 块
  mainText = appendExternalDisplayBlocks(mainText, cleanText);
  const optionRaw = extractTag(cleanText, 'option');
  const summary = extractTag(cleanText, 'sum');

  // 提取 UpdateVariable / update 中的内容
  const updateVarBlock = extractTagByPriority(cleanText, ['UpdateVariable', 'update']);
  const jsonPatch = extractTag(updateVarBlock, 'JSONPatch');
  const variableUpdate = updateVarBlock || jsonPatch;

  // 解析所有选项行
  const allOptions = parseOptions(optionRaw);

  // 检测 E 选项和 [Leave]
  const hasOptionE = allOptions.some(line => /^E\.\s/i.test(line));
  const hasLeave = allOptions.some(isLeaveOptionLine);
  const hasRebirth = allOptions.some(isRebirthOptionLine);

  // 过滤掉 E 和 [Leave]，只保留 A-D 等普通选项
  const normalOptions = allOptions.filter(line => {
    if (/^E\.\s/i.test(line)) return false;
    if (isLeaveOptionLine(line)) return false;
    if (isRebirthOptionLine(line)) return false;
    return true;
  });

  return {
    mainText,
    options: normalOptions,
    summary,
    variableUpdate,
    jsonPatch,
    rawText: cleanText,
    hasOptionE,
    hasLeave,
    hasRebirth,
  };
}

/**
 * 从已有消息文本中快速提取 <sum> 小总结
 * 用于读档面板列表显示
 */
export function extractSummary(messageText: string, options?: ResponseParserOptions): string {
  const clean = getParserSourceText(messageText, options);
  return extractTag(clean, 'sum');
}

/**
 * 从已有消息文本中快速提取 <maintext> 正文
 */
export function extractMainText(messageText: string, options?: ResponseParserOptions): string {
  const clean = getParserSourceText(messageText, options);
  const mainTextRaw = extractMainTagByPriority(clean, ['maintext', 'maintxt', 'content', '正文']);
  let mainText = removeHtmlComments(mainTextRaw);
  const mainHasTucao = /<\s*\/?\s*(?:tucao|吐槽)\b|\[\s*\/?\s*tucao\s*]|&lt;\s*\/?\s*tucao\b/i.test(mainTextRaw);
  if (!mainHasTucao) {
    const fallbackTucao = extractTucaoBlocks(clean);
    if (fallbackTucao.length > 0) {
      const merged = fallbackTucao.map(block => `<tucao>\n${block}\n</tucao>`).join('\n\n');
      mainText = [mainText, merged].filter(part => part && part.trim().length > 0).join('\n\n');
    }
  }
  // <image>/<img> 标签内容始终显示，追加正文外的 image 块
  mainText = appendExternalDisplayBlocks(mainText, clean);
  return mainText;
}

/**
 * 从已有消息文本中只提取正文标签本体。
 * 不追加正文外的 catsay / SexualScene / image 等展示块。
 */
export function extractMainTextOnly(messageText: string, options?: ResponseParserOptions): string {
  const clean = getParserSourceText(messageText, options);
  const mainTextRaw = extractMainTagByPriority(clean, ['maintext', 'maintxt', 'content', '正文']);
  return removeHtmlComments(mainTextRaw);
}

/**
 * 从已有消息文本中快速提取变量更新块（<UpdateVariable> / <update>）
 */
export function extractVariableUpdate(messageText: string, options?: ResponseParserOptions): string {
  const clean = getParserSourceText(messageText, options);
  return extractTagByPriority(clean, ['UpdateVariable', 'update']);
}

/**
 * 从已有消息文本中快速提取 <option> 选项（仅普通 A-D 选项）
 */
export function extractOptions(messageText: string, options?: ResponseParserOptions): string[] {
  const clean = getParserSourceText(messageText, options);
  const allOptions = parseOptions(extractTag(clean, 'option'));
  return allOptions.filter(line => {
    if (/^E\.\s/i.test(line)) return false;
    if (isLeaveOptionLine(line)) return false;
    if (isRebirthOptionLine(line)) return false;
    return true;
  });
}

/**
 * 从已有消息文本中检测是否含有 E 选项
 */
export function detectOptionE(messageText: string, options?: ResponseParserOptions): boolean {
  const clean = getParserSourceText(messageText, options);
  const allOptions = parseOptions(extractTag(clean, 'option'));
  return allOptions.some(line => /^E\.\s/i.test(line));
}

/**
 * 从已有消息文本中检测是否含有 [Leave]
 */
export function detectLeave(messageText: string, options?: ResponseParserOptions): boolean {
  const clean = getParserSourceText(messageText, options);
  const allOptions = parseOptions(extractTag(clean, 'option'));
  return allOptions.some(isLeaveOptionLine);
}

/**
 * 从已有消息文本中检测是否含有 [Rebirth]
 */
export function detectRebirth(messageText: string, options?: ResponseParserOptions): boolean {
  const clean = getParserSourceText(messageText, options);
  const allOptions = parseOptions(extractTag(clean, 'option'));
  return allOptions.some(isRebirthOptionLine);
}
